using Contoso.Services;

namespace Contoso.Services.Tests;

public interface IGreeter { }
public sealed class Greeter : IGreeter { }

public interface ILogger { }
public sealed class Logger : ILogger { }

[TestClass]
public sealed class ServiceRegistryTests
{
    private readonly ServiceRegistry _registry;

    public ServiceRegistryTests()
    {
        _registry = new ServiceRegistry();
    }

    [TestMethod]
    public void Register_AndResolve_ReturnsSameInstance()
    {
        // Arrange
        var greeter = new Greeter();

        // Act
        _registry.Register<IGreeter>(greeter);
        var resolved = _registry.Resolve<IGreeter>();

        // Assert
        Assert.AreSame(greeter, resolved);
    }

    [TestMethod]
    public void Resolve_UnregisteredService_ReturnsNull()
    {
        var result = _registry.Resolve<IGreeter>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _registry.Register<IGreeter>(null!));

        Assert.AreEqual("service", ex.ParamName);
    }

    [TestMethod]
    public void ResolveRequired_UnregisteredService_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _registry.ResolveRequired<IGreeter>());
    }

    [TestMethod]
    public void Clear_RemovesAllServices()
    {
        // Arrange
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(new Logger());

        // Act
        _registry.Clear();

        // Assert
        Assert.IsNull(_registry.Resolve<IGreeter>());
        Assert.IsNull(_registry.Resolve<ILogger>());
        Assert.IsEmpty(_registry.GetAll());
    }

    [TestMethod]
    public void Remove_RegisteredService_ResolvesToNull()
    {
        // Arrange
        _registry.Register<IGreeter>(new Greeter());

        // Act
        _registry.Remove<IGreeter>();

        // Assert
        Assert.IsNull(_registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Remove_DoesNotAffectOtherServices()
    {
        // Arrange
        var logger = new Logger();
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(logger);

        // Act
        _registry.Remove<IGreeter>();

        // Assert
        Assert.AreSame(logger, _registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegistered()
    {
        // Arrange
        var greeter = new Greeter();
        var logger = new Logger();
        _registry.Register<IGreeter>(greeter);
        _registry.Register<ILogger>(logger);

        // Act
        var all = _registry.GetAll();

        // Assert
        Assert.HasCount(2, all);
        Assert.Contains(greeter, all);
        Assert.Contains(logger, all);
    }

    [TestMethod]
    public void Register_SameType_OverwritesPrevious()
    {
        // Arrange
        var first = new Greeter();
        var second = new Greeter();

        // Act
        _registry.Register<IGreeter>(first);
        _registry.Register<IGreeter>(second);

        // Assert
        Assert.AreSame(second, _registry.Resolve<IGreeter>());
    }
}

